/**
 * MedX elevation theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Surface elevation levels for nested panels.
 */
const ELEVATION_TOKENS = Object.freeze({
  primary: { value: "theme-elevation-primary", scope: "theme" },
  secondary: { value: "theme-elevation-secondary", scope: "theme" },
  muted: { value: "theme-elevation-muted", scope: "theme" },
  accent: { value: "theme-elevation-accent", scope: "theme" },
  surface: { value: "theme-elevation-surface", scope: "theme" },
});

const ELEVATION_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const ELEVATION_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const elevationRegistry = new Map();
const ELEVATION_listeners = new Set();
let ELEVATION_seq = 0;

function createElevationId(prefix = "medx-theme-elevation") {
  ELEVATION_seq += 1;
  return `${prefix}-${ELEVATION_seq}`;
}

function registerElevation(config = {}) {
  const entryId = config.id ?? createElevationId();
  const preset = ELEVATION_PRESETS[config.preset ?? "default"] ?? ELEVATION_PRESETS.default;
  const token = ELEVATION_TOKENS[config.token ?? preset.token] ?? ELEVATION_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: ELEVATION_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  elevationRegistry.set(entryId, entry);
  notifyElevationListeners("register", entry);
  return entry;
}

function updateElevation(id, patch = {}) {
  const entry = elevationRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyElevationListeners("update", entry);
  return entry;
}

function resolveElevation(id) {
  const entry = elevationRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listElevationEntries(filter = {}) {
  let items = Array.from(elevationRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onElevationEvent(listener) {
  ELEVATION_listeners.add(listener);
  return () => ELEVATION_listeners.delete(listener);
}

function notifyElevationListeners(type, entry) {
  for (const listener of ELEVATION_listeners) {
    try {
      listener({ type, entry, registrySize: elevationRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:elevation] listener error", err.message);
    }
  }
}

function getElevationMetrics() {
  const items = listElevationEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(ELEVATION_TOKENS).length,
    presets: Object.keys(ELEVATION_PRESETS).length,
  };
}

async function runMedxElevation() {
  console.log("[medx:ui:theme:elevation] runtime initialized");
  console.log(`[medx:ui:theme:elevation] tokens=${Object.keys(ELEVATION_TOKENS).length} presets=${Object.keys(ELEVATION_PRESETS).length}`);

  const events = [];
  onElevationEvent((e) => events.push(e.type));

  const domains = Object.keys(ELEVATION_SUPPLY_CHAIN);
  const presets = Object.keys(ELEVATION_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerElevation({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/elevation" },
    });
  }

  const first = listElevationEntries()[0];
  if (first) updateElevation(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getElevationMetrics();
  const resolved = first ? resolveElevation(first.id) : null;

  console.log(`[medx:ui:theme:elevation] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:elevation] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:elevation] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:elevation] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:elevation] bootstrap complete");
}

module.exports = runMedxElevation;
